        { id: 'networking', label: 'Networking' },
        { id: 'security', label: 'Security' },
        { id: 'monitoring', label: 'Monitoring' },
      ],
      [],
    );

    const options = useMemo<Option[]>(
      () => [
        {
          id: 'creating',
          label: 'Creating',
          variant: 'warning',
        },
        {
          id: 'deleting',
          label: 'Deleting',
          variant: 'danger',
        },
        {
          id: 'failed',
          label: 'Failed',
          variant: 'danger',
        },
